commands.examples:
SELECT * FROM users;
SELECT id, username, email FROM users WHERE is_active = TRUE;
SELECT * FROM products WHERE price BETWEEN 100 AND 500;
SELECT * FROM users WHERE role IN ('admin', 'moderator');
SELECT * FROM users WHERE email LIKE '%@gmail.com';
SELECT * FROM orders ORDER BY created_at DESC LIMIT 10;
SELECT * FROM products ORDER BY price ASC LIMIT 20 OFFSET 40;
SELECT DISTINCT city FROM users;
SELECT COUNT(*) AS total, role FROM users GROUP BY role HAVING total > 5;

INSERT INTO users (username, email, password_hash) VALUES ('john', 'john@mail.com', 'hash123');

-- Multiple insert
INSERT INTO products (name, price) VALUES
  ('Laptop', 15000000),
  ('Mouse', 250000),
  ('Keyboard', 750000);

-- Upsert
INSERT INTO settings (user_id, theme) VALUES (1, 'dark')
ON DUPLICATE KEY UPDATE theme = VALUES(theme);

-- Insert from select
INSERT INTO archive_orders SELECT * FROM orders WHERE created_at < '2024-01-01';

UPDATE users SET role = 'admin' WHERE id = 1;
UPDATE products SET price = price * 1.1 WHERE category = 'electronics';
UPDATE users SET is_active = FALSE WHERE last_login < '2024-01-01';
UPDATE orders SET status = 'shipped', shipped_at = NOW() WHERE id = 42;

DELETE FROM users WHERE id = 5;
DELETE FROM logs WHERE created_at < '2024-01-01';
DELETE FROM sessions WHERE expires_at < NOW();
DELETE FROM products ORDER BY created_at ASC LIMIT 10;
